function initDatepick($id){setTimeout(function(){const DatePicker=MCDatepicker.create({el:"#"+$id,bodyType:"modal",autoClose:false,closeOndblclick:true,closeOnBlur:false,customOkBTN:"OK",customClearBTN:datapickerLang[$lang].customClearBTN,customCancelBTN:datapickerLang[$lang].customCancelBTN,firstWeekday:datapickerLang[$lang].firstWeekday,dateFormat:"DD.MM.YYYY",customWeekDays:datapickerLang[$lang].customWeekDays,customMonths:datapickerLang[$lang].customMonths})},500)}